mapper.select:
SELECT /*CsFaqMapper.getTotalCount */ COUNT(BOARD_SEQ) FROM NMCP_BOARD_BAS WHERE BOARD_CTG_SEQ = 57 AND VIEW_YN = 'Y'
AND SBST_CTG = #{sbstCtg}
AND ( REPLACE(UPPER(BOARD_SUBJECT),' ','') LIKE '%' || UPPER(#{searchNm}) || '%' || '%' ESCAPE '!' OR REPLACE(UPPER(BOARD_CONTENTS),' ','') LIKE '%' || UPPER(#{searchNm}) || '%' || '%' ESCAPE '!')

SELECT	BOARD_CONTENTS
FROM	NMCP_BOARD_BAS
WHERE	BOARD_SEQ = #{getAnswer}

SELECT RNUM , BOARD_SEQ , SBST_CTG , BOARD_SUBJECT , BOARD_HIT_CNT , BOARD_CONTENTS FROM ( SELECT ROW_NUMBER() OVER ( ORDER BY CASE WHEN REPLACE(UPPER(BOARD_SUBJECT), ' ', '') LIKE '%' || REPLACE(UPPER(#{searchNm}), ' ', '') || '%' ESCAPE '!' THEN 1 ELSE 2 END, BOARD_HIT_CNT DESC ) AS RNUM , BOARD_SEQ , SBST_CTG , BOARD_SUBJECT , BOARD_HIT_CNT , BOARD_CONTENTS FROM NMCP_BOARD_BAS WHERE BOARD_CTG_SEQ = 57 AND VIEW_YN = 'Y'
AND ( REPLACE(UPPER(BOARD_SUBJECT), ' ', '') LIKE '%' || REPLACE(UPPER(#{searchNm}), ' ', '') || '%' ESCAPE '!' OR REPLACE(UPPER(BOARD_CONTENTS), ' ', '') LIKE '%' || REPLACE(UPPER(#{searchNm}), ' ', '') || '%' ESCAPE '!' )
) WHERE RNUM <= #{selectCnt}
